simple_types.code:
type Compression_Level is (
  Level_0,
  Level_1,
  Level_2,
  Level_3
);

subprograms.code:
generic
  with function  Read_Byte return Byte;
  with function  More_Bytes return Boolean;
  with procedure Write_Byte (b : Byte);
procedure Encode
  (level                  : Compression_Level           := Level_1;
   literal_context_bits   : Literal_Context_Bits_Range  := 3;
   literal_position_bits  : Literal_Position_Bits_Range := 0;
   position_bits          : Position_Bits_Range         := 2;
   end_marker             : Boolean := True;
   uncompressed_size_info : Boolean := False;
   dictionary_size        : Natural := Default_dictionary_size)
